import { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import { Menu, X, } from "lucide-react";
import LogoCtx from "./img/logo.png"
import "./Header_style.css";

const Header = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const location = useLocation();

  const navigation = [
    { name: "Home", href: "/" },
    { name: "Serviços", href: "/servicos" },
    { name: "Planos", href: "/planos" },
    { name: "Sobre", href: "/sobre" },
    { name: "Blog", href: "/blog" },
    { name: "Contato", href: "/contato" },
  ];

  const isActive = (path) => location.pathname === path;
  const handleLinkClick = () => {
    setIsMenuOpen(false);
  };

  return (
    <header className="header">
      <div className="header-container">
        <nav className="navbar">
          <Link to="/" className="logo-link">
            <img src={LogoCtx} alt="Logo Cortex Studio" className="logo-image" />
            <span className="logo-text">Cortex Studio</span>
          </Link>


          <div className="desktop-nav">
            <div className="nav-links">
              {navigation.map((item) => (
                <Link
                  key={item.name}
                  to={item.href}
                  className={`nav-link ${isActive(item.href) ? "active" : ""}`}
                >
                  {item.name}
                </Link>
              ))}
            </div>
          </div>

          {/* Mobile Menu Button */}
          <button
            className="mobile-menu-button"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            aria-label="Toggle menu"
          >
            {isMenuOpen ? (
              <X className="mobile-menu-icon" />
            ) : (
              <Menu className="mobile-menu-icon" />
            )}
          </button>
        </nav>

        {/* Mobile Navigation */}
        {isMenuOpen && (
          <div className="mobile-nav">
            <div className="mobile-nav-stack">
              {navigation.map((item) => (
                <Link
                  key={item.name}
                  to={item.href}
                  className={`nav-link ${isActive(item.href) ? "active" : ""}`}
                  onClick={handleLinkClick}
                >
                  {item.name}
                </Link>
              ))}
              <a
                href="https://wa.me/5511999999999?text=Olá, quero agendar um serviço com a Cortex Studio"
                target="_blank"
                rel="noopener noreferrer"
                className="cta-button"
              >
                WhatsApp
              </a>
            </div>
          </div>
        )}
      </div>
    </header>
  );
};

export default Header;
